module top_module(
	input clock, reset,
	input [7:0] multiplicand, multiplier,
	input Load_regs, Add_dec,
	output reg [15:0] PR,
	output Zero
);reg [7:0] AR, BR;
always @(posedge clock, posedge reset)
	if (reset) begin
		AR <= 8'b0;
		BR <= 8'b0;
		PR <= 16'b0;
	end else if (Load_regs) begin
		AR <= multiplier;
		BR <= multiplicand;
		PR <= 16'b0;
	end else if (Add_dec) begin
		PR <= PR + BR;
		AR <= AR - 1;
	end

  wire _n01 = AR[0] ^ 8'b0[0];
  wire _n02 = AR[1] ^ 8'b0[1];
  wire _n03 = AR[2] ^ 8'b0[2];
  wire _n04 = AR[3] ^ 8'b0[3];
  assign Zero = ~_n01 & ~_n02 & ~_n03 & ~_n04;
endmodule
